import React, { useState, useMemo, useEffect, useCallback } from "react"
import Layout from "../components/Layout"
import DealCard from "../components/DealCard"
import dealsData from "../../data/deals.json"
import { useLocation } from "@reach/router"
import { navigate } from "gatsby"

const monthlyEquiv = (d) => {
  if (d.price.monthly) return d.price.monthly
  if (d.price.hourly) return d.price.hourly * 730
  if (d.price.monthlyPerGB) return d.price.monthlyPerGB * 10
  if (d.price.inputPer1M) return d.price.inputPer1M * 5
  if (d.price.annual) return d.price.annual / 12
  if (d.price.annualPrice) return d.price.annualPrice / 12
  return 99999
}

const DealsPage = () => {
  const { deals } = dealsData
  const location = useLocation()

  const getParams = () => new URLSearchParams(location?.search || "")

  const [category, setCategory] = useState(() => getParams().get("category") || "all")
  const [provider, setProvider] = useState(() => getParams().get("provider") || "all")
  const [sort, setSort] = useState(() => getParams().get("sort") || "cheapest")
  const [search, setSearch] = useState(() => getParams().get("q") || "")
  const [mounted, setMounted] = useState(false)

  useEffect(() => { setMounted(true) }, [])

  // Re-sync from URL on back/forward
  useEffect(() => {
    const p = getParams()
    const c = p.get("category") || "all"
    const pr = p.get("provider") || "all"
    const s = p.get("sort") || "cheapest"
    const q = p.get("q") || ""
    setCategory(c); setProvider(pr); setSort(s); setSearch(q)
  }, [location?.search])

  const categories = useMemo(() => ["all", ...new Set(deals.map(d => d.category))], [deals])
  const providers = useMemo(() => ["all", ...new Set(deals.map(d => d.provider))].sort(), [deals])

  const filtered = useMemo(() => {
    let result = deals.filter(d => {
      const catMatch = category === "all" || d.category === category
      const provMatch = provider === "all" || d.provider === provider
      const q = search.toLowerCase()
      const searchMatch = !q ||
        d.name.toLowerCase().includes(q) ||
        d.provider.toLowerCase().includes(q) ||
        (d.tags && d.tags.some(t => t.toLowerCase().includes(q))) ||
        (d.features && d.features.some(f => f.toLowerCase().includes(q))) ||
        Object.values(d.specs || {}).some(v => String(v).toLowerCase().includes(q))
      return catMatch && provMatch && searchMatch
    })

    result.sort((a, b) => {
      const pa = monthlyEquiv(a), pb = monthlyEquiv(b)
      switch (sort) {
        case "cheapest": return pa - pb
        case "expensive": return pb - pa
        case "provider": return a.provider.localeCompare(b.provider)
        case "name": return a.name.localeCompare(b.name)
        default: return pa - pb
      }
    })
    return result
  }, [deals, category, provider, sort, search])

  const updateURL = useCallback((key, value) => {
    const p = new URLSearchParams(location?.search || "")
    if (value && value !== "all" && value !== "") p.set(key, value)
    else p.delete(key)
    const qs = p.toString()
    navigate(`${location?.pathname || "/deals/"}${qs ? "?" + qs : ""}`, { replace: true })
  }, [location])

  const activeFilters = []
  if (category !== "all") activeFilters.push({ key: "category", label: category.replace("-", " "), value: category })
  if (provider !== "all") activeFilters.push({ key: "provider", label: provider, value: provider })
  if (search) activeFilters.push({ key: "q", label: `"${search}"`, value: search })

  const clearFilter = (key) => {
    if (key === "category") { setCategory("all"); updateURL("category", "all") }
    if (key === "provider") { setProvider("all"); updateURL("provider", "all") }
    if (key === "q") { setSearch(""); updateURL("q", "") }
  }

  const resetAll = () => {
    setCategory("all"); setProvider("all"); setSort("cheapest"); setSearch("")
    navigate(location?.pathname || "/deals/", { replace: true })
  }

  // Don't render interactive content until client-side hydration
  if (!mounted) {
    return (
      <Layout activeNav="deals">
        <div className="page-header">
          <h1>All Deals</h1>
          <p className="page-subtitle">Loading...</p>
        </div>
      </Layout>
    )
  }

  return (
    <Layout activeNav="deals">
      <div className="page-header">
        <h1>All Deals</h1>
        <p className="page-subtitle">
          {deals.length} deals across {categories.length - 1} perks · Verified pricing
        </p>
      </div>

      <div className="filter-bar">
        <div className="filter-row">
          <div className="filter-search">
            <span className="filter-search-icon">🔍</span>
            <input
              type="text"
              placeholder="Search deals, providers, specs, tags..."
              value={search}
              onChange={e => { setSearch(e.target.value); updateURL("q", e.target.value) }}
            />
          </div>
          <select
            className="filter-select"
            value={category}
            onChange={e => { setCategory(e.target.value); updateURL("category", e.target.value) }}
          >
            {categories.map(c => (
              <option key={c} value={c}>
                {c === "all" ? "All Perks" : c.replace("-", " ")}
              </option>
            ))}
          </select>
          <select
            className="filter-select"
            value={provider}
            onChange={e => { setProvider(e.target.value); updateURL("provider", e.target.value) }}
          >
            {providers.map(p => (
              <option key={p} value={p}>
                {p === "all" ? "All Providers" : p}
              </option>
            ))}
          </select>
          <select
            className="filter-select"
            value={sort}
            onChange={e => setSort(e.target.value)}
          >
            <option value="cheapest">Cheapest First</option>
            <option value="expensive">Most Expensive First</option>
            <option value="provider">Provider A–Z</option>
            <option value="name">Name A–Z</option>
          </select>
          <span className="filter-count">{filtered.length} deal{filtered.length !== 1 ? "s" : ""}</span>
        </div>

        {activeFilters.length > 0 && (
          <div className="filter-pills">
            {activeFilters.map(f => (
              <span key={f.key} className="filter-pill" onClick={() => clearFilter(f.key)}>
                {f.label} <span className="filter-pill-x">×</span>
              </span>
            ))}
            <button className="filter-reset" onClick={resetAll}>Reset all</button>
          </div>
        )}
      </div>

      <div className="deal-grid">
        {filtered.map(d => <DealCard key={d.id} deal={d} />)}
      </div>

      {filtered.length === 0 && (
        <div className="no-results">
          <p>No deals match your filters.</p>
          <p style={{ marginTop: "0.5rem", fontSize: "0.8rem" }}>Try removing some filters or changing your search.</p>
        </div>
      )}
    </Layout>
  )
}

export const Head = () => (
  <>
    <title>All Deals — DevBundles</title>
    <meta name="description" content="Browse all verified infrastructure deals — VPS, GPU, domains, storage, and AI APIs. Infrastructure costs only." />
  </>
)

export default DealsPage
