import React from "react"

const DealCard = ({ deal }) => {
  const formatPrice = (d) => {
    if (d.price.monthly) return { value: `$${d.price.monthly}`, unit: "/mo" }
    if (d.price.annual) return { value: `$${d.price.annual}`, unit: "/yr" }
    if (d.price.annualPrice) return { value: `$${d.price.annualPrice}`, unit: "/yr" }
    if (d.price.monthlyPerGB) return { value: `$${d.price.monthlyPerGB}`, unit: "/GB/mo" }
    if (d.price.hourly) return { value: `$${d.price.hourly}`, unit: "/hr" }
    if (d.price.inputPer1M) return { value: `$${d.price.inputPer1M}`, unit: "/1M in" }
    return { value: "See site", unit: "" }
  }

  const categoryIcons = {
    vps: "🖥️", gpu: "🎮", domain: "🌐", storage: "💾", serverless: "⚡", "ai-api": "🧠"
  }

  const price = formatPrice(deal)

  return (
    <article className="deal-card">
      <div className="deal-card-header">
        <span className="deal-card-icon">{categoryIcons[deal.category] || "📦"}</span>
        <span className={`deal-card-badge ${deal.uncertain ? "unverified" : "verified"}`}>
          {deal.uncertain ? "Verify" : "Verified"}
        </span>
      </div>
      <div className="deal-card-provider">{deal.provider}</div>
      <h4 className="deal-card-name">{deal.name}</h4>

      {Object.keys(deal.specs).length > 0 && (
        <div className="deal-card-specs">
          {Object.entries(deal.specs).map(([k, v]) => (
            <div key={k}><span>{k}:</span> {v}</div>
          ))}
        </div>
      )}

      <div className="deal-card-price">
        <span className="deal-card-price-value">{price.value}</span>
        <span className="deal-card-price-unit">{price.unit}</span>
        {deal.price.currency !== "USD" && <span className="deal-card-price-currency">{deal.price.currency}</span>}
      </div>

      {deal.features && deal.features.length > 0 && (
        <div className="deal-card-features">
          {deal.features.slice(0, 4).map((f, i) => (
            <span key={i} className="deal-card-feature">{f}</span>
          ))}
        </div>
      )}

      <a href={deal.url} target="_blank" rel="noopener noreferrer" className="deal-card-link">
        Visit {deal.provider} →
      </a>
    </article>
  )
}

export default DealCard
